var r=[{id:"ciclo",nome:"Ciclo Menstrual",icone:"water-outline",cor:"#C2185B",corClara:"#FCE4EC",resumo:"Como funciona o ciclo e porque \xE9 importante conhec\xEA-lo.",conteudo:[{titulo:"O que \xE9 o ciclo menstrual?",texto:"O ciclo menstrual \xE9 o processo natural e recorrente pelo qual o corpo da mulher se prepara mensalmente para uma poss\xEDvel gravidez. Em m\xE9dia dura entre 21 a 35 dias, contados do primeiro dia de uma menstrua\xE7\xE3o at\xE9 ao primeiro dia da seguinte, embora isto varie de pessoa para pessoa."},{titulo:"As fases do ciclo",texto:"O ciclo divide-se em quatro fases principais: a fase menstrual (elimina\xE7\xE3o do revestimento do \xFAtero), a fase folicular (prepara\xE7\xE3o de um novo \xF3vulo), a ovula\xE7\xE3o (liberta\xE7\xE3o do \xF3vulo, por volta do meio do ciclo) e a fase l\xFAtea (prepara\xE7\xE3o do corpo para uma eventual gravidez)."},{titulo:"Porque vale a pena monitorizar",texto:"Registar a dura\xE7\xE3o e regularidade do ciclo ajuda a identificar padr\xF5es normais, antecipar a menstrua\xE7\xE3o e detetar mais cedo altera\xE7\xF5es que mere\xE7am aten\xE7\xE3o m\xE9dica, como ciclos muito irregulares ou c\xF3licas muito intensas."}]},{id:"gravidez",nome:"Gravidez",icone:"heart-outline",cor:"#7B2D8E",corClara:"#F3E5F5",resumo:"Sinais, cuidados e acompanhamento durante a gesta\xE7\xE3o.",conteudo:[{titulo:"Sinais iniciais comuns",texto:"Atraso menstrual, sensibilidade nos seios, n\xE1useas (sobretudo matinais) e cansa\xE7o s\xE3o sinais frequentemente associados ao in\xEDcio da gravidez. Um teste de gravidez e a confirma\xE7\xE3o m\xE9dica s\xE3o a forma fi\xE1vel de a confirmar."},{titulo:"A import\xE2ncia das consultas pr\xE9-natais",texto:"O acompanhamento m\xE9dico regular ao longo da gravidez permite monitorizar o desenvolvimento do beb\xE9, detetar precocemente complica\xE7\xF5es e aconselhar sobre alimenta\xE7\xE3o, suplementa\xE7\xE3o (como o \xE1cido f\xF3lico) e estilo de vida adequados a cada fase."},{titulo:"Cuidados gerais recomendados",texto:"Uma alimenta\xE7\xE3o equilibrada, hidrata\xE7\xE3o adequada, evitar \xE1lcool e tabaco, e manter atividade f\xEDsica moderada (sempre com orienta\xE7\xE3o m\xE9dica) s\xE3o pilares importantes para uma gravidez saud\xE1vel."}]},{id:"nutricao",nome:"Nutri\xE7\xE3o",icone:"nutrition-outline",cor:"#00897B",corClara:"#E0F2F1",resumo:"Nutrientes essenciais em diferentes fases da vida da mulher.",conteudo:[{titulo:"Ferro e \xE1cido f\xF3lico",texto:"Devido \xE0 perda de sangue durante a menstrua\xE7\xE3o, as mulheres t\xEAm necessidades de ferro mais elevadas. O \xE1cido f\xF3lico \xE9 especialmente importante antes e durante a gravidez, pois contribui para o desenvolvimento saud\xE1vel do sistema nervoso do feto."},{titulo:"C\xE1lcio e vitamina D",texto:"Estes nutrientes s\xE3o essenciais para a sa\xFAde \xF3ssea, particularmente relevantes na perimenopausa e menopausa, per\xEDodo em que o risco de osteoporose aumenta devido \xE0 diminui\xE7\xE3o do estrog\xE9nio."},{titulo:"H\xE1bitos alimentares equilibrados",texto:"Uma dieta variada, rica em vegetais, frutas, prote\xEDna de boa qualidade e gorduras saud\xE1veis, associada \xE0 hidrata\xE7\xE3o adequada, ajuda a manter energia est\xE1vel e a regular o ciclo hormonal."}]},{id:"mental",nome:"Sa\xFAde Mental",icone:"happy-outline",cor:"#F57C00",corClara:"#FFF3E0",resumo:"Bem-estar emocional e o impacto das hormonas no humor.",conteudo:[{titulo:"Hormonas e humor",texto:"As varia\xE7\xF5es hormonais ao longo do ciclo menstrual podem influenciar o humor, a energia e a irritabilidade \u2014 \xE9 o que se conhece popularmente como s\xEDndrome pr\xE9-menstrual (TPM), que afeta a maioria das mulheres em algum grau."},{titulo:"Quando procurar ajuda",texto:"Sintomas como tristeza persistente, ansiedade intensa ou altera\xE7\xF5es de humor que interferem significativamente no dia a dia merecem aten\xE7\xE3o profissional. Per\xEDodos como o p\xF3s-parto tamb\xE9m exigem vigil\xE2ncia especial, devido ao risco de depress\xE3o p\xF3s-parto."},{titulo:"H\xE1bitos que ajudam",texto:"Sono regular, atividade f\xEDsica, gest\xE3o do stress e manter rela\xE7\xF5es sociais de apoio s\xE3o fatores que contribuem positivamente para o equil\xEDbrio emocional ao longo da vida."}]},{id:"prevencao",nome:"Exames Preventivos",icone:"shield-checkmark-outline",cor:"#1976D2",corClara:"#E3F2FD",resumo:"Exames de rotina que ajudam a detetar problemas a tempo.",conteudo:[{titulo:"Citologia (Papanicolau)",texto:"\xC9 um exame de rastreio que permite detetar altera\xE7\xF5es nas c\xE9lulas do colo do \xFAtero antes de se tornarem um problema grave, incluindo sinais precoces associados ao HPV. A periodicidade recomendada deve ser discutida com um profissional de sa\xFAde."},{titulo:"Exame da mama e mamografia",texto:"A autopalpa\xE7\xE3o regular ajuda a conhecer o pr\xF3prio corpo, mas n\xE3o substitui os exames cl\xEDnicos e a mamografia, que s\xE3o as ferramentas mais eficazes para a dete\xE7\xE3o precoce do cancro da mama, especialmente a partir de determinadas idades."},{titulo:"Consultas de ginecologia regulares",texto:"Consultas peri\xF3dicas permitem acompanhar a sa\xFAde reprodutiva, esclarecer d\xFAvidas sobre contrace\xE7\xE3o e identificar precocemente qualquer altera\xE7\xE3o que necessite de tratamento."}]},{id:"fertilidade",nome:"Fertilidade",icone:"leaf-outline",cor:"#388E3C",corClara:"#E8F5E9",resumo:"Como funciona a janela f\xE9rtil e o que pode influenci\xE1-la.",conteudo:[{titulo:"A janela f\xE9rtil",texto:"A janela f\xE9rtil corresponde aos dias do ciclo em que a probabilidade de conce\xE7\xE3o \xE9 maior \u2014 geralmente os dias que antecedem a ovula\xE7\xE3o e o pr\xF3prio dia da ovula\xE7\xE3o, j\xE1 que o \xF3vulo permanece vi\xE1vel apenas durante um curto per\xEDodo."},{titulo:"Fatores que influenciam a fertilidade",texto:"Idade, peso, stress, tabagismo e determinadas condi\xE7\xF5es de sa\xFAde (como s\xEDndrome do ov\xE1rio poliqu\xEDstico ou endometriose) podem influenciar a fertilidade. Um estilo de vida equilibrado ajuda a apoiar a sa\xFAde reprodutiva."},{titulo:"Quando procurar avalia\xE7\xE3o especializada",texto:"Se houver dificuldade em conceber ap\xF3s um per\xEDodo prolongado de tentativa (normalmente discutido com um profissional), pode ser \xFAtil procurar uma avalia\xE7\xE3o de fertilidade para identificar poss\xEDveis causas e op\xE7\xF5es."}]},{id:"menopausa",nome:"Menopausa",icone:"sunny-outline",cor:"#E65100",corClara:"#FBE9E7",resumo:"Uma fase natural de transi\xE7\xE3o, com sintomas e cuidados pr\xF3prios.",conteudo:[{titulo:"O que \xE9 a menopausa",texto:"A menopausa marca o fim natural dos ciclos menstruais, geralmente diagnosticada ap\xF3s 12 meses consecutivos sem menstrua\xE7\xE3o. \xC9 precedida por uma fase de transi\xE7\xE3o chamada perimenopausa, onde os n\xEDveis hormonais come\xE7am a variar."},{titulo:"Sintomas comuns",texto:"Ondas de calor, altera\xE7\xF5es do sono, mudan\xE7as de humor e secura vaginal s\xE3o sintomas frequentemente relatados, resultantes da diminui\xE7\xE3o do estrog\xE9nio. A intensidade varia bastante de mulher para mulher."},{titulo:"Cuidados nesta fase",texto:"Manter uma alimenta\xE7\xE3o rica em c\xE1lcio e vitamina D, praticar exerc\xEDcio f\xEDsico regular e fazer o acompanhamento m\xE9dico s\xE3o formas importantes de cuidar da sa\xFAde \xF3ssea, cardiovascular e emocional durante e ap\xF3s a menopausa."}]},{id:"contracepcao",nome:"Contrace\xE7\xE3o",icone:"shield-half-outline",cor:"#5E35B1",corClara:"#EDE7F6",resumo:"M\xE9todos dispon\xEDveis e como escolher o mais adequado.",conteudo:[{titulo:"Tipos de m\xE9todos contracetivos",texto:"Existem v\xE1rios m\xE9todos contracetivos: hormonais (p\xEDlula, implante, DIU hormonal), de barreira (preservativo), DIU de cobre, e m\xE9todos permanentes. Cada um tem diferente efic\xE1cia, forma de uso e efeitos associados."},{titulo:"Como escolher o m\xE9todo adequado",texto:"A escolha do m\xE9todo contracetivo deve considerar o hist\xF3rico de sa\xFAde, estilo de vida, planos reprodutivos futuros e prefer\xEAncias pessoais. Uma consulta com um profissional de sa\xFAde ajuda a encontrar a op\xE7\xE3o mais adequada."},{titulo:"Contrace\xE7\xE3o de emerg\xEAncia",texto:"A contrace\xE7\xE3o de emerg\xEAncia pode ser usada ap\xF3s uma rela\xE7\xE3o sexual desprotegida ou falha do m\xE9todo habitual, mas n\xE3o deve substituir um m\xE9todo contracetivo regular, sendo mais eficaz quanto mais cedo for utilizada."}]},{id:"exercicio",nome:"Exerc\xEDcio F\xEDsico",icone:"barbell-outline",cor:"#0277BD",corClara:"#E1F5FE",resumo:"Benef\xEDcios da atividade f\xEDsica em cada fase da vida.",conteudo:[{titulo:"Benef\xEDcios gerais",texto:"A atividade f\xEDsica regular ajuda a regular o ciclo hormonal, melhora a sa\xFAde cardiovascular, fortalece os ossos e m\xFAsculos, e tem um impacto positivo comprovado no humor e na gest\xE3o do stress."},{titulo:"Exerc\xEDcio durante a gravidez",texto:"Em gravidezes sem complica\xE7\xF5es, a atividade f\xEDsica moderada (como caminhada, nata\xE7\xE3o ou yoga pr\xE9-natal) \xE9 geralmente segura e ben\xE9fica, mas deve ser sempre orientada por um profissional de sa\xFAde."},{titulo:"Adapta\xE7\xE3o ao longo do ciclo",texto:"A energia e disposi\xE7\xE3o para o exerc\xEDcio podem variar ao longo do ciclo menstrual devido \xE0s flutua\xE7\xF5es hormonais. Ouvir o pr\xF3prio corpo e ajustar a intensidade do treino pode tornar a pr\xE1tica mais sustent\xE1vel."}]},{id:"sono",nome:"Sono e Bem-Estar",icone:"moon-outline",cor:"#3949AB",corClara:"#E8EAF6",resumo:"A import\xE2ncia do descanso para o equil\xEDbrio hormonal e mental.",conteudo:[{titulo:"Sono e hormonas",texto:"O sono de qualidade \xE9 essencial para a regula\xE7\xE3o hormonal. Altera\xE7\xF5es hormonais durante o ciclo menstrual, gravidez ou menopausa podem afetar a qualidade do sono, criando um ciclo que merece aten\xE7\xE3o."},{titulo:"H\xE1bitos de higiene do sono",texto:"Manter hor\xE1rios regulares, evitar ecr\xE3s antes de dormir, criar um ambiente escuro e fresco, e evitar cafe\xEDna \xE0 tarde s\xE3o h\xE1bitos que favorecem um sono mais reparador."},{titulo:"Sono e sa\xFAde mental",texto:"A priva\xE7\xE3o de sono est\xE1 associada a maior irritabilidade, dificuldade de concentra\xE7\xE3o e impacto negativo no humor. Cuidar do sono \xE9, por isso, tamb\xE9m uma forma de cuidar da sa\xFAde mental."}]}],o=[{id:1,temaId:"ciclo",pergunta:"Em m\xE9dia, quantos dias dura um ciclo menstrual?",opcoes:["Entre 5 a 10 dias","Entre 21 a 35 dias","Exatamente 14 dias","Entre 40 a 60 dias"],respostaCorreta:1,explicacao:"O ciclo menstrual costuma durar entre 21 e 35 dias, variando de pessoa para pessoa, sendo 28 dias apenas uma m\xE9dia de refer\xEAncia.",curiosidade:'A palavra "menstrua\xE7\xE3o" vem do latim "mensis", que significa m\xEAs \u2014 uma refer\xEAncia \xE0 sua regularidade aproximadamente mensal.'},{id:2,temaId:"gravidez",pergunta:"Qual destes \xE9 um sinal inicial comum de gravidez?",opcoes:["Aumento da menstrua\xE7\xE3o","Atraso menstrual","Queda de cabelo s\xFAbita","Febre alta"],respostaCorreta:1,explicacao:"O atraso menstrual \xE9 um dos primeiros sinais frequentemente associados \xE0 gravidez.",curiosidade:"A dura\xE7\xE3o m\xE9dia de uma gravidez \xE9 de 40 semanas, contadas a partir do primeiro dia da \xFAltima menstrua\xE7\xE3o \u2014 e n\xE3o do momento da conce\xE7\xE3o."},{id:3,temaId:"nutricao",pergunta:"Porque \xE9 que as mulheres t\xEAm, em geral, maior necessidade de ferro?",opcoes:["Devido \xE0 perda de sangue durante a menstrua\xE7\xE3o","Porque comem menos carne","N\xE3o h\xE1 diferen\xE7a em rela\xE7\xE3o aos homens","Porque praticam mais exerc\xEDcio"],respostaCorreta:0,explicacao:"A perda de sangue menstrual aumenta a necessidade de ferro para evitar anemia.",curiosidade:"Alimentos como feij\xE3o, espinafre e carnes vermelhas s\xE3o boas fontes de ferro \u2014 combin\xE1-los com vitamina C ajuda o corpo a absorv\xEA-lo melhor."},{id:4,temaId:"mental",pergunta:"O que \xE9 a TPM (s\xEDndrome pr\xE9-menstrual)?",opcoes:["Uma doen\xE7a rara","Altera\xE7\xF5es de humor e energia ligadas \xE0s varia\xE7\xF5es hormonais do ciclo","Um sinal sempre de gravidez","Algo que s\xF3 afeta adolescentes"],respostaCorreta:1,explicacao:"A TPM est\xE1 relacionada com as varia\xE7\xF5es hormonais do ciclo menstrual e afeta a maioria das mulheres em algum grau.",curiosidade:"Estima-se que at\xE9 3 de cada 4 mulheres sintam algum sintoma de TPM em algum momento da vida reprodutiva."},{id:5,temaId:"prevencao",pergunta:"Para que serve a citologia (exame de Papanicolau)?",opcoes:["Detetar altera\xE7\xF5es nas c\xE9lulas do colo do \xFAtero","Medir a tens\xE3o arterial","Avaliar a vis\xE3o","Diagnosticar diabetes"],respostaCorreta:0,explicacao:"A citologia \xE9 um exame de rastreio que deteta precocemente altera\xE7\xF5es nas c\xE9lulas do colo do \xFAtero, incluindo sinais associados ao HPV.",curiosidade:"O exame recebe o nome do m\xE9dico grego Georgios Papanikolaou, que o desenvolveu na d\xE9cada de 1920."},{id:6,temaId:"fertilidade",pergunta:'O que \xE9 a "janela f\xE9rtil"?',opcoes:["Qualquer dia do ciclo","Os dias com maior probabilidade de conce\xE7\xE3o, \xE0 volta da ovula\xE7\xE3o","Apenas o \xFAltimo dia do ciclo","Um conceito sem relev\xE2ncia m\xE9dica"],respostaCorreta:1,explicacao:"A janela f\xE9rtil corresponde aos dias com maior probabilidade de conce\xE7\xE3o, pr\xF3ximos da ovula\xE7\xE3o.",curiosidade:"O \xF3vulo permanece vi\xE1vel para fecunda\xE7\xE3o durante apenas 12 a 24 horas ap\xF3s a ovula\xE7\xE3o, mas os espermatozoides podem sobreviver v\xE1rios dias no corpo."},{id:7,temaId:"menopausa",pergunta:"Como se define geralmente a menopausa?",opcoes:["Ap\xF3s 1 m\xEAs sem menstruar","Ap\xF3s 12 meses consecutivos sem menstrua\xE7\xE3o","Apenas por sintomas f\xEDsicos","N\xE3o tem uma defini\xE7\xE3o m\xE9dica"],respostaCorreta:1,explicacao:"A menopausa \xE9 geralmente diagnosticada ap\xF3s 12 meses consecutivos sem menstrua\xE7\xE3o.",curiosidade:"A idade m\xE9dia da menopausa natural situa-se entre os 45 e os 55 anos, mas pode variar bastante entre mulheres."},{id:8,temaId:"contracepcao",pergunta:"Qual destes \xE9 um exemplo de m\xE9todo contracetivo de barreira?",opcoes:["P\xEDlula","Preservativo","DIU hormonal","Implante"],respostaCorreta:1,explicacao:"O preservativo \xE9 o exemplo cl\xE1ssico de m\xE9todo contracetivo de barreira.",curiosidade:"O preservativo \xE9 o \xFAnico m\xE9todo contracetivo que tamb\xE9m ajuda a prevenir a transmiss\xE3o de infe\xE7\xF5es sexualmente transmiss\xEDveis."},{id:9,temaId:"exercicio",pergunta:"Qual destes \xE9 um benef\xEDcio comprovado da atividade f\xEDsica regular?",opcoes:["N\xE3o tem impacto na sa\xFAde hormonal","Ajuda a regular o ciclo hormonal e melhora o humor","Aumenta sempre o risco de les\xF5es graves","\xC9 prejudicial em qualquer fase da vida"],respostaCorreta:1,explicacao:"A atividade f\xEDsica regular contribui para a regula\xE7\xE3o hormonal e para o bem-estar emocional.",curiosidade:'O exerc\xEDcio f\xEDsico estimula a liberta\xE7\xE3o de endorfinas, conhecidas como as "hormonas da felicidade", que ajudam a reduzir o stress.'},{id:10,temaId:"sono",pergunta:"Qual a rela\xE7\xE3o entre sono e hormonas?",opcoes:["N\xE3o existe qualquer rela\xE7\xE3o","O sono de qualidade \xE9 essencial para a regula\xE7\xE3o hormonal","O sono s\xF3 afeta o peso corporal","As hormonas n\xE3o influenciam o sono"],respostaCorreta:1,explicacao:"O sono de qualidade \xE9 importante para a regula\xE7\xE3o hormonal, e esta tamb\xE9m pode afetar o sono.",curiosidade:"A maior parte da produ\xE7\xE3o de melatonina, a hormona do sono, ocorre durante a noite e \xE9 sens\xEDvel \xE0 exposi\xE7\xE3o \xE0 luz artificial antes de dormir."},{id:11,temaId:"ciclo",pergunta:"A ovula\xE7\xE3o ocorre, geralmente, em que fase do ciclo?",opcoes:["No primeiro dia da menstrua\xE7\xE3o","A meio do ciclo","Nunca tem um padr\xE3o","Apenas em ciclos irregulares"],respostaCorreta:1,explicacao:"A ovula\xE7\xE3o ocorre normalmente a meio do ciclo, quando o \xF3vulo \xE9 libertado.",curiosidade:'Algumas mulheres sentem uma ligeira dor de um dos lados da barriga durante a ovula\xE7\xE3o, conhecida informalmente como "dor do meio do ciclo" (mittelschmerz).'},{id:12,temaId:"gravidez",pergunta:"Qual suplemento \xE9 especialmente recomendado antes e durante a gravidez?",opcoes:["Vitamina C em altas doses","\xC1cido f\xF3lico","Cafe\xEDna","Prote\xEDna em p\xF3"],respostaCorreta:1,explicacao:"O \xE1cido f\xF3lico \xE9 fundamental antes e durante a gravidez, contribuindo para o desenvolvimento saud\xE1vel do sistema nervoso do feto.",curiosidade:"Recomenda-se come\xE7ar a tomar \xE1cido f\xF3lico idealmente antes da conce\xE7\xE3o, j\xE1 que o tubo neural do beb\xE9 se forma nas primeiras semanas de gravidez."},{id:13,temaId:"nutricao",pergunta:"Quais nutrientes s\xE3o especialmente importantes na menopausa para a sa\xFAde \xF3ssea?",opcoes:["C\xE1lcio e vitamina D","Vitamina C apenas","Apenas prote\xEDna","A\xE7\xFAcares simples"],respostaCorreta:0,explicacao:"O c\xE1lcio e a vitamina D ajudam a proteger a sa\xFAde \xF3ssea, especialmente relevante quando o estrog\xE9nio diminui na menopausa.",curiosidade:"A pele produz vitamina D quando exposta \xE0 luz solar, mas muitas pessoas precisam tamb\xE9m de a obter atrav\xE9s da alimenta\xE7\xE3o ou suplementa\xE7\xE3o."},{id:14,temaId:"mental",pergunta:"Em que per\xEDodo \xE9 especialmente importante vigiar a sa\xFAde mental devido ao risco de depress\xE3o?",opcoes:["P\xF3s-parto","Apenas na adolesc\xEAncia","Apenas ap\xF3s os 60 anos","N\xE3o h\xE1 per\xEDodo de maior risco"],respostaCorreta:0,explicacao:"O per\xEDodo p\xF3s-parto exige vigil\xE2ncia especial devido ao risco de depress\xE3o p\xF3s-parto.",curiosidade:"A depress\xE3o p\xF3s-parto pode surgir em qualquer altura no primeiro ano ap\xF3s o parto, n\xE3o apenas nas primeiras semanas."},{id:15,temaId:"prevencao",pergunta:"A autopalpa\xE7\xE3o da mama substitui a mamografia?",opcoes:["Sim, completamente","N\xE3o, s\xE3o complementares e a mamografia \xE9 mais eficaz na dete\xE7\xE3o precoce","A mamografia j\xE1 n\xE3o \xE9 recomendada","Nenhuma delas \xE9 necess\xE1ria"],respostaCorreta:1,explicacao:"A autopalpa\xE7\xE3o ajuda a conhecer o pr\xF3prio corpo, mas n\xE3o substitui os exames cl\xEDnicos e a mamografia, mais eficazes na dete\xE7\xE3o precoce.",curiosidade:"A mamografia consegue detetar altera\xE7\xF5es muito antes de serem palp\xE1veis, por vezes anos antes de se tornarem percet\xEDveis ao toque."},{id:16,temaId:"fertilidade",pergunta:"Qual destes fatores pode influenciar a fertilidade?",opcoes:["Cor dos olhos","Idade e estilo de vida","Altura","Tipo de sangue"],respostaCorreta:1,explicacao:"A idade, o peso, o stress e h\xE1bitos como o tabagismo podem influenciar a fertilidade.",curiosidade:"A reserva de \xF3vulos de uma mulher \xE9 definida ainda antes do nascimento e diminui naturalmente ao longo da vida."},{id:17,temaId:"menopausa",pergunta:"Qual destes \xE9 um sintoma comum da menopausa?",opcoes:["Ondas de calor","Crescimento acelerado de cabelo","Aumento da vis\xE3o","Febre persistente"],respostaCorreta:0,explicacao:"As ondas de calor s\xE3o um dos sintomas mais comuns associados \xE0 menopausa.",curiosidade:"As ondas de calor podem durar entre alguns segundos e v\xE1rios minutos, e a sua frequ\xEAncia varia muito de mulher para mulher."},{id:18,temaId:"contracepcao",pergunta:"O que deve ser considerado ao escolher um m\xE9todo contracetivo?",opcoes:["Apenas o pre\xE7o","Hist\xF3rico de sa\xFAde, estilo de vida e prefer\xEAncias pessoais","A cor da embalagem","Nenhum fator \xE9 relevante"],respostaCorreta:1,explicacao:"A escolha do m\xE9todo deve considerar sa\xFAde, estilo de vida e prefer\xEAncias, idealmente com apoio m\xE9dico.",curiosidade:"Existem mais de 15 m\xE9todos contracetivos diferentes dispon\xEDveis atualmente, com efic\xE1cias e formas de uso muito distintas."},{id:19,temaId:"exercicio",pergunta:"O exerc\xEDcio moderado durante a gravidez \xE9 geralmente...",opcoes:["Sempre proibido","Seguro e ben\xE9fico em gravidezes sem complica\xE7\xF5es, com orienta\xE7\xE3o m\xE9dica","S\xF3 permitido no \xFAltimo trimestre","Irrelevante para a sa\xFAde da gestante"],respostaCorreta:1,explicacao:"Em gravidezes sem complica\xE7\xF5es, o exerc\xEDcio moderado \xE9 geralmente seguro com acompanhamento adequado.",curiosidade:"Atividades como caminhada, nata\xE7\xE3o e yoga pr\xE9-natal s\xE3o frequentemente recomendadas por serem de baixo impacto nas articula\xE7\xF5es."},{id:20,temaId:"sono",pergunta:"Qual destes h\xE1bitos favorece um sono mais reparador?",opcoes:["Usar ecr\xE3s at\xE9 tarde na cama","Manter hor\xE1rios regulares e evitar cafe\xEDna \xE0 tarde","Dormir em ambiente muito iluminado","Variar a hora de dormir todos os dias"],respostaCorreta:1,explicacao:"Hor\xE1rios regulares e evitar cafe\xEDna \xE0 tarde s\xE3o h\xE1bitos de higiene do sono recomendados.",curiosidade:"A luz azul emitida por telem\xF3veis e tablets pode atrasar a produ\xE7\xE3o natural de melatonina, dificultando o adormecer."},{id:21,temaId:"ciclo",pergunta:"Porque \xE9 \xFAtil monitorizar o ciclo menstrual?",opcoes:["N\xE3o tem qualquer utilidade","S\xF3 serve para quem quer engravidar","Ajuda a identificar padr\xF5es normais e altera\xE7\xF5es a vigiar","\xC9 apenas uma curiosidade sem valor m\xE9dico"],respostaCorreta:2,explicacao:"Monitorizar o ciclo ajuda a conhecer o pr\xF3prio corpo e a identificar precocemente irregularidades que possam merecer aten\xE7\xE3o m\xE9dica.",curiosidade:"Hoje existem aplica\xE7\xF5es e m\xE9todos simples (como calend\xE1rios ou di\xE1rios) que ajudam a registar padr\xF5es do ciclo ao longo dos meses."},{id:22,temaId:"gravidez",pergunta:"Qual a import\xE2ncia das consultas pr\xE9-natais?",opcoes:["Servem apenas para marcar a data do parto","Permitem monitorizar a sa\xFAde da m\xE3e e do beb\xE9 ao longo da gesta\xE7\xE3o","S\xE3o opcionais e raramente necess\xE1rias","S\xF3 s\xE3o importantes no \xFAltimo m\xEAs"],respostaCorreta:1,explicacao:"As consultas pr\xE9-natais regulares permitem acompanhar o desenvolvimento do beb\xE9 e detetar precocemente eventuais complica\xE7\xF5es.",curiosidade:"As ecografias pr\xE9-natais permitem n\xE3o s\xF3 ver o desenvolvimento do beb\xE9, mas tamb\xE9m estimar a idade gestacional com boa precis\xE3o."},{id:23,temaId:"nutricao",pergunta:"O que caracteriza uma alimenta\xE7\xE3o equilibrada para a sa\xFAde hormonal?",opcoes:["Eliminar totalmente as gorduras","Variedade de vegetais, frutas, prote\xEDna e gorduras saud\xE1veis","Comer apenas um tipo de alimento por dia","Reduzir ao m\xEDnimo a ingest\xE3o de \xE1gua"],respostaCorreta:1,explicacao:"Uma dieta variada e equilibrada ajuda a manter energia est\xE1vel e a regular o ciclo hormonal.",curiosidade:"Algumas gorduras saud\xE1veis, como as presentes no azeite e nos frutos secos, s\xE3o importantes para a produ\xE7\xE3o de hormonas no corpo."},{id:24,temaId:"mental",pergunta:"Qual destes h\xE1bitos ajuda a manter o equil\xEDbrio emocional?",opcoes:["Isolamento social","Sono irregular","Atividade f\xEDsica regular","Evitar qualquer rotina"],respostaCorreta:2,explicacao:"A atividade f\xEDsica regular, junto com sono adequado, contribui positivamente para o bem-estar emocional.",curiosidade:"Manter liga\xE7\xF5es sociais positivas est\xE1 associado a melhores n\xEDveis de bem-estar emocional ao longo da vida, em qualquer idade."},{id:25,temaId:"prevencao",pergunta:"Qual a vantagem de consultas de ginecologia regulares?",opcoes:["N\xE3o trazem qualquer vantagem","Permitem acompanhar a sa\xFAde reprodutiva e detetar problemas precocemente","Servem apenas para quem est\xE1 gr\xE1vida","S\xE3o apenas para emerg\xEAncias"],respostaCorreta:1,explicacao:"Consultas regulares permitem acompanhar a sa\xFAde reprodutiva e identificar precocemente altera\xE7\xF5es que necessitem de tratamento.",curiosidade:"Especialistas recomendam que a primeira consulta de ginecologia ocorra geralmente entre os 13 e os 15 anos, ou antes se houver alguma preocupa\xE7\xE3o."},{id:26,temaId:"fertilidade",pergunta:"Quando pode ser \xFAtil procurar uma avalia\xE7\xE3o de fertilidade?",opcoes:["Nunca \xE9 necess\xE1rio","Ap\xF3s dificuldade prolongada em conceber","Apenas antes dos 20 anos","Apenas se j\xE1 tiver tido filhos"],respostaCorreta:1,explicacao:"Dificuldade prolongada em conceber pode justificar uma avalia\xE7\xE3o especializada de fertilidade.",curiosidade:"A avalia\xE7\xE3o de fertilidade pode envolver tanto a mulher como o parceiro, j\xE1 que fatores de ambos podem influenciar a conce\xE7\xE3o."},{id:27,temaId:"menopausa",pergunta:"Que cuidados s\xE3o especialmente importantes na menopausa?",opcoes:["Reduzir ao m\xEDnimo a atividade f\xEDsica","Cuidar da sa\xFAde \xF3ssea, cardiovascular e emocional","Evitar todo o tipo de consultas m\xE9dicas","N\xE3o h\xE1 cuidados especiais nesta fase"],respostaCorreta:1,explicacao:"A sa\xFAde \xF3ssea, cardiovascular e emocional merecem aten\xE7\xE3o especial durante e ap\xF3s a menopausa.",curiosidade:"Ap\xF3s a menopausa, o risco cardiovascular tende a aumentar, tornando ainda mais relevante manter h\xE1bitos de vida saud\xE1veis."},{id:28,temaId:"contracepcao",pergunta:"A contrace\xE7\xE3o de emerg\xEAncia deve ser usada como...",opcoes:["M\xE9todo contracetivo regular","Recurso pontual ap\xF3s falha do m\xE9todo habitual","Substituto do preservativo a longo prazo","Nenhuma das op\xE7\xF5es"],respostaCorreta:1,explicacao:"A contrace\xE7\xE3o de emerg\xEAncia \xE9 um recurso pontual e n\xE3o deve substituir um m\xE9todo regular.",curiosidade:"A efic\xE1cia da contrace\xE7\xE3o de emerg\xEAncia diminui com o tempo, sendo mais eficaz quanto mais cedo for tomada ap\xF3s a rela\xE7\xE3o desprotegida."},{id:29,temaId:"exercicio",pergunta:"Porque pode a disposi\xE7\xE3o para o exerc\xEDcio variar ao longo do ciclo?",opcoes:["Por acaso, sem motivo","Devido \xE0s flutua\xE7\xF5es hormonais do ciclo menstrual","Porque o exerc\xEDcio n\xE3o tem rela\xE7\xE3o com hormonas","Apenas por falta de motiva\xE7\xE3o"],respostaCorreta:1,explicacao:"As flutua\xE7\xF5es hormonais ao longo do ciclo podem influenciar os n\xEDveis de energia e disposi\xE7\xE3o.",curiosidade:"Algumas atletas ajustam a intensidade dos treinos conforme a fase do ciclo em que se encontram, adaptando-se aos n\xEDveis de energia."},{id:30,temaId:"sono",pergunta:"A priva\xE7\xE3o de sono est\xE1 associada a...",opcoes:["Melhor concentra\xE7\xE3o","Maior irritabilidade e dificuldade de concentra\xE7\xE3o","Nenhum efeito percet\xEDvel","Melhoria do humor"],respostaCorreta:1,explicacao:"A priva\xE7\xE3o de sono est\xE1 associada a maior irritabilidade e dificuldade de concentra\xE7\xE3o.",curiosidade:"Adultos geralmente precisam de 7 a 9 horas de sono por noite para um funcionamento f\xEDsico e mental adequado."}];function i(a){let e=(a-1)*10;return o.slice(e,e+10)}export{r as a,i as b};
